import * as t from "io-ts";
import { AccelerationIntent } from "./accelerationIntent";
import { EthBuildOptionsWithoutFeeOptions } from "./ethBuildOptions";
import { FeeOption } from "./feeOption";
import { EIP1559FeeOptions } from "./eip1559FeeOptions";

/**
 * @title ETH Acceleration Intent
 */
export const EthAccelerationIntent = t.intersection([
  AccelerationIntent,
  EthBuildOptionsWithoutFeeOptions,
  t.type({
    feeOptions: t.union([FeeOption, EIP1559FeeOptions]),
  }),
]);

export type EthAccelerationIntent = t.TypeOf<typeof EthAccelerationIntent>;
